# Category: datastore_security

import re
from flask import Flask, request, jsonify
import redis

app = Flask(__name__)

redis_client = redis.Redis(host='localhost', port=6379, db=0, decode_responses=True)

ALLOWED_COMMANDS = {
    'GET', 'SET', 'DEL', 'EXISTS', 'EXPIRE', 'TTL', 'PTTL',
    'KEYS', 'SCAN', 'TYPE', 'RENAME',
    'MGET', 'MSET', 'SETNX', 'SETEX', 'PSETEX', 'GETSET',
    'INCR', 'INCRBY', 'INCRBYFLOAT', 'DECR', 'DECRBY',
    'APPEND', 'STRLEN', 'GETRANGE', 'SETRANGE',
    'HGET', 'HSET', 'HDEL', 'HEXISTS', 'HGETALL', 'HKEYS',
    'HVALS', 'HLEN', 'HMGET', 'HMSET', 'HINCRBY', 'HINCRBYFLOAT',
    'LPUSH', 'RPUSH', 'LPOP', 'RPOP', 'LLEN', 'LRANGE',
    'LINDEX', 'LSET', 'LREM', 'LTRIM',
    'SADD', 'SREM', 'SISMEMBER', 'SMEMBERS', 'SCARD',
    'SUNION', 'SINTER', 'SDIFF',
    'ZADD', 'ZREM', 'ZSCORE', 'ZRANK', 'ZRANGE', 'ZREVRANGE',
    'ZRANGEBYSCORE', 'ZCARD', 'ZCOUNT',
    'PING', 'ECHO', 'INFO', 'DBSIZE', 'RANDOMKEY',
    'PERSIST', 'PEXPIRE', 'EXPIREAT', 'PEXPIREAT',
    'DUMP', 'OBJECT',
}

BLOCKED_COMMANDS = {
    'FLUSHALL', 'FLUSHDB', 'SHUTDOWN', 'CONFIG', 'DEBUG',
    'SLAVEOF', 'REPLICAOF', 'CLUSTER', 'EVAL', 'EVALSHA',
    'SCRIPT', 'MODULE', 'ACL', 'BGSAVE', 'BGREWRITEAOF',
    'SAVE', 'MONITOR', 'SUBSCRIBE', 'PSUBSCRIBE', 'PUBLISH',
    'CLIENT', 'COMMAND', 'MIGRATE', 'MOVE', 'SWAPDB',
    'SELECT', 'AUTH', 'QUIT', 'RESET',
}

MAX_COMMAND_LENGTH = 1024
MAX_ARGS = 20


def parse_command_string(command_string):
    """Parse a command string into command name and arguments safely."""
    parts = []
    current = []
    in_quotes = False
    quote_char = None

    for char in command_string:
        if in_quotes:
            if char == quote_char:
                in_quotes = False
            else:
                current.append(char)
        elif char in ('"', "'"):
            in_quotes = True
            quote_char = char
        elif char == ' ':
            if current:
                parts.append(''.join(current))
                current = []
        else:
            current.append(char)

    if current:
        parts.append(''.join(current))

    return parts


def validate_command(command_name):
    """Validate that the command is allowed."""
    cmd_upper = command_name.upper()

    if cmd_upper in BLOCKED_COMMANDS:
        return False, f"Command '{cmd_upper}' is blocked for security reasons."

    if cmd_upper not in ALLOWED_COMMANDS:
        return False, f"Command '{cmd_upper}' is not in the allowed commands list."

    return True, None


def sanitize_input(value):
    """Basic input sanitization."""
    if not isinstance(value, str):
        return str(value)
    # Remove null bytes
    value = value.replace('\x00', '')
    return value


@app.route('/api/admin/redis', methods=['POST'])
def execute_redis_command():
    """Execute a Redis command from user input with validation."""
    api_key = request.headers.get('X-API-Key')
    if not api_key or api_key != app.config.get('ADMIN_API_KEY', 'change-me-in-production'):
        return jsonify({
            'success': False,
            'error': 'Unauthorized. Valid API key required.'
        }), 401

    command_string = request.args.get('command', '').strip()

    if not command_string:
        return jsonify({
            'success': False,
            'error': 'No command provided. Use ?command=<redis_command>'
        }), 400

    if len(command_string) > MAX_COMMAND_LENGTH:
        return jsonify({
            'success': False,
            'error': f'Command exceeds maximum length of {MAX_COMMAND_LENGTH} characters.'
        }), 400

    parts = parse_command_string(command_string)

    if not parts:
        return jsonify({
            'success': False,
            'error': 'Could not parse command.'
        }), 400

    if len(parts) > MAX_ARGS + 1:
        return jsonify({
            'success': False,
            'error': f'Too many arguments. Maximum is {MAX_ARGS}.'
        }), 400

    command_name = parts[0]
    command_args = [sanitize_input(arg) for arg in parts[1:]]

    is_valid, error_message = validate_command(command_name)
    if not is_valid:
        return jsonify({
            'success': False,
            'error': error_message
        }), 403

    try:
        result = redis_client.execute_command(command_name, *command_args)

        # Convert bytes to strings if needed
        if isinstance(result, bytes):
            result = result.decode('utf-8', errors='replace')
        elif isinstance(result, list):
            result = [
                item.decode('utf-8', errors='replace') if isinstance(item, bytes) else item
                for item in result
            ]
        elif isinstance(result, dict):
            result = {
                (k.decode('utf-8', errors='replace') if isinstance(k, bytes) else k):
                (v.decode('utf-8', errors='replace') if isinstance(v, bytes) else v)
                for k, v in result.items()
            }

        return jsonify({
            'success': True,
            'command': command_name.upper(),
            'args': command_args,
            'result': result
        }), 200

    except redis.ConnectionError:
        return jsonify({
            'success': False,
            'error': 'Could not connect to Redis server.'
        }), 503
    except redis.ResponseError as e:
        return jsonify({
            'success': False,
            'error': f'Redis error: {str(e)}'
        }), 400
    except Exception as e:
        return jsonify({
            'success': False,
            'error': f'Unexpected error: {str(e)}'
        }), 500


@app.route('/api/admin/redis/allowed-commands', methods=['GET'])
def list_allowed_commands():
    """List all allowed Redis commands."""
    api_key = request.headers.get('X-API-Key')
    if not api_key or api_key != app.config.get('ADMIN_API_KEY', 'change-me-in-production'):
        return jsonify({
            'success': False,
            'error': 'Unauthorized. Valid API key required.'
        }), 401

    return jsonify({
        'success': True,
        'allowed_commands': sorted(list(ALLOWED_COMMANDS)),
        'blocked_commands': sorted(list(BLOCKED_COMMANDS))
    }), 200


@app.route('/api/admin/redis/health', methods=['GET'])
def redis_health():
    """Check Redis connection health."""
    try:
        redis_client.ping()
        info = redis_client.info(section='server')
        return jsonify({
            'success': True,
            'status': 'healthy',
            'redis_version': info.get('redis_version', 'unknown'),
            'uptime_seconds': info.get('uptime_in_seconds', 'unknown')
        }), 200
    except redis.ConnectionError:
        return jsonify({
            'success': False,
            'status': 'unhealthy',
            'error': 'Cannot connect to Redis.'
        }), 503


